#include <string.h>

#include "jv.h"

int LLVMFuzzerTestOneInput(uint8_t *data, size_t size) {
  // Creat null-terminated string
  char *null_terminated = (char *)malloc(size + 1);
  memcpy(null_terminated, (char *)data, size);
  null_terminated[size] = '\0';

  // Fuzzer entrypoint
  jv res = jv_parse(null_terminated);
  jv_free(res);

  // Free the null-terminated string
  free(null_terminated);

  return 0;
}

#include <stdint.h>
#include <stdlib.h>
#include <string.h>

#include "jv.h"

int LLVMFuzzerTestOneInput(uint8_t *data, size_t size) {
  if (size < 8) {
    return 0;
  }

  int fuzz_flags = *(int*)data;
  data += 4;
  size -= 4;
  int dump_flags = *(int*)data;
  data += 4;
  size -= 4;

  // Creat null-terminated string
  char *null_terminated = (char *)malloc(size + 1);
  memcpy(null_terminated, (char *)data, size);
  null_terminated[size] = '\0';

  // Fuzzer entrypoint
  jv res = jv_parse_custom_flags(null_terminated, fuzz_flags);
  if (jv_is_valid(res)) {
    jv_dump(res, dump_flags);
  } else {
    jv_free(res);
  }

  // Free the null-terminated string
  free(null_terminated);

  return 0;
}

#include "coap3/coap_internal.h"

int
LLVMFuzzerTestOneInput(const uint8_t *data, size_t size) {
  int i;

  if (size < 1)
    return 0;

  for (i = 0; i < 256; i++) {
    coap_binary_t *tag = get_asn1_tag(i, data, size, NULL);

    coap_delete_binary(tag);
  }

  return 0;
}

#include "coap3/coap_internal.h"

int
LLVMFuzzerTestOneInput(const uint8_t *data, size_t size) {
  coap_oscore_conf_t *oscore_conf;
  coap_str_const_t conf_mem;
  cose_encrypt0_t cose[1];
  uint8_t *buf;

  if (size < 1)
    return 0;

  /* Initialize libcoap */
  coap_startup();
  coap_set_log_level(COAP_LOG_EMERG);

  /* The coap_new_oscore_conf() API expects null-terminated input data. */
  buf = (uint8_t *)malloc(size + 1);
  if (buf == NULL) {
    coap_cleanup();
    return 0;
  }
  memcpy(buf, data, size);
  buf[size] = '\0';

  /* Initialisation */
  conf_mem.s = buf;
  conf_mem.length = size + 1;

  /* Attempt to parse the fuzzer input as OSCORE configuration */
  oscore_conf = coap_new_oscore_conf(conf_mem, NULL, NULL, 0);

  /* Clean up if parsing succeeded */
  if (oscore_conf) {
    coap_delete_oscore_conf(oscore_conf);
  }

  free(buf);

  /* Attempt to decode OSCORE option value */
  cose_encrypt0_init(cose);
  oscore_decode_option_value(data, size, cose);

  coap_cleanup();
  return 0;
}

